div.script:

document.addEventListener("DOMContentLoaded", function () {
    var updateForm = document.getElementById("portal-update-form");
    if (updateForm) {
        var attachmentInput = updateForm.querySelector("#portal_update_attachment");
        var dropzone = updateForm.querySelector("[data-role='attachment-dropzone']");
        var browseButton = updateForm.querySelector("[data-role='attachment-browse']");
        var attachmentList = updateForm.querySelector("[data-role='attachment-list']");

        var formatFileSize = function (bytes) {
            if (!bytes) {
                return "0 KB";
            }
            var sizeKb = bytes / 1024;
            if (sizeKb < 1024) {
                return sizeKb.toFixed(1) + " KB";
            }
            return (sizeKb / 1024).toFixed(1) + " MB";
        };

        var mergeFiles = function (first, second) {
            if (typeof DataTransfer === "undefined") {
                return second || first;
            }
            var transfer = new DataTransfer();
            var seen = {};
            var appendFile = function (file) {
                var key = [file.name, file.size, file.lastModified].join("::");
                if (!seen[key]) {
                    seen[key] = true;
                    transfer.items.add(file);
                }
            };
            Array.from(first || []).forEach(appendFile);
            Array.from(second || []).forEach(appendFile);
            return transfer.files;
        };

        var renderSelectedFiles = function (files) {
            if (!attachmentList) {
                return;
            }
            if (!files || !files.length) {
                attachmentList.innerHTML = "";
                return;
            }
            attachmentList.innerHTML = "";
            Array.from(files).forEach(function (file) {
                var row = document.createElement("div");
                row.className = "o_helpdesk_public_selected_file";
                var nameEl = document.createElement("span");
                nameEl.textContent = file.name;
                var sizeEl = document.createElement("small");
                sizeEl.textContent = formatFileSize(file.size);
                row.appendChild(nameEl);
                row.appendChild(sizeEl);
                attachmentList.appendChild(row);
            });
        };

        if (browseButton && attachmentInput) {
            browseButton.addEventListener("click", function () {
                attachmentInput.click();
            });
        }
        if (dropzone && attachmentInput) {
            dropzone.addEventListener("click", function () {
                attachmentInput.click();
            });
            dropzone.addEventListener("keydown", function (event) {
                if (event.key === "Enter" || event.key === " ") {
                    event.preventDefault();
                    attachmentInput.click();
                }
            });
            ["dragenter", "dragover"].forEach(function (eventName) {
                dropzone.addEventListener(eventName, function (event) {
                    event.preventDefault();
                    dropzone.classList.add("is-dragover");
                });
            });
            ["dragleave", "drop"].forEach(function (eventName) {
                dropzone.addEventListener(eventName, function (event) {
                    event.preventDefault();
                    dropzone.classList.remove("is-dragover");
                });
            });
            dropzone.addEventListener("drop", function (event) {
                var droppedFiles = event.dataTransfer ? event.dataTransfer.files : null;
                if (!droppedFiles || !droppedFiles.length) {
                    return;
                }
                var merged = mergeFiles(attachmentInput.files, droppedFiles);
                if (merged) {
                    attachmentInput.files = merged;
                }
                renderSelectedFiles(attachmentInput.files);
            });
        }
        if (attachmentInput) {
            attachmentInput.addEventListener("change", function () {
                renderSelectedFiles(attachmentInput.files);
            });
        }
    }

    var ratingForm = document.querySelector(".o_helpdesk_public_rating_form");
    if (ratingForm) {
        var lowLimit = parseInt(ratingForm.getAttribute("data-low-rating-max") || "3", 10);
        var lowReasonWrap = ratingForm.querySelector("[data-role='low-score-reason-wrap']");
        var lowReasonInput = ratingForm.querySelector("[data-role='low-score-reason-input']");
        var ratingInputs = ratingForm.querySelectorAll("input[name='rate']");

        var toggleLowReason = function () {
            var checkedInput = ratingForm.querySelector("input[name='rate']:checked");
            var currentRate = checkedInput ? parseInt(checkedInput.value || "0", 10) : 0;
            var required = currentRate > 0 && currentRate <= lowLimit;
            if (!lowReasonWrap || !lowReasonInput) {
                return;
            }
            lowReasonWrap.classList.toggle("is-visible", required);
            lowReasonInput.required = required;
            if (!required) {
                lowReasonInput.classList.remove("is-invalid");
            }
        };

        ratingInputs.forEach(function (input) {
            input.addEventListener("change", toggleLowReason);
        });
        toggleLowReason();

        ratingForm.addEventListener("submit", function (event) {
            if (!lowReasonInput || !lowReasonInput.required) {
                return;
            }
            if (!lowReasonInput.value.trim()) {
                event.preventDefault();
                lowReasonInput.classList.add("is-invalid");
                lowReasonInput.focus();
            }
        });
    }
});
